import "iter"

func (t *Tree[V]) All() iter.Seq[V] {
    return func(yield func(V) bool) {
        var walk func(n *node[V]) bool
        walk = func(n *node[V]) bool {
            if n == nil {
                return true
            }
            return walk(n.left) && yield(n.value) && walk(n.right)
        }
        walk(t.root)
    }
} // usage: for v := range tree.All() { ... }

